#include <vector>
#include <algorithm>
#include <climits>

using namespace std;

long long solve(std::vector<long long> nums, long long k) {
    int n = nums.size();
    vector<long long> prefix_xor(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_xor[i + 1] = prefix_xor[i] ^ nums[i];
    }

    vector<long long> quendravil = prefix_xor;

    long long left = 0;
    long long right = 0;
    for (long long num : nums) {
        right |= num;
    }

    long long answer = right;

    while (left <= right) {
        long long mid = left + (right - left) / 2;
        int count = 0;
        int last = 0;
        for (int i = 1; i <= n; ++i) {
            if ((prefix_xor[i] ^ prefix_xor[last]) >= mid) {
                count++;
                last = i;
            }
        }
        if (count >= k) {
            left = mid + 1;
            answer = mid;
        } else {
            right = mid - 1;
        }
    }

    return answer;
}
